from pyspark import pipelines as dp

rules = {
    "non_null_id":    "order_id IS NOT NULL",
    "valid_amount":   "amount BETWEEN 0 AND 1000000",
    "valid_currency": "currency IN ('USD','EUR','GBP')"
}

@dp.table()
@dp.expect_all(rules)
def silver_orders():
    return spark.readStream.table("bronze.orders")
